import{_ as e,o as a,c as n,a3 as s}from"./chunks/framework.CjquFG0V.js";const p=JSON.parse('{"title":"57A. Community Health Teams Staffing Establishment","description":"","frontmatter":{"title":"57A. Community Health Teams Staffing Establishment","eba":"Mental Health Services 2024-2028","topics":["consultation","preliminary","staffing"]},"headers":[],"relativePath":"ebas/mental-health/common-terms/staffing/57A-community-health-teams-staffing-establishment.md","filePath":"ebas/mental-health/common-terms/staffing/57A-community-health-teams-staffing-establishment.md"}'),m={name:"ebas/mental-health/common-terms/staffing/57A-community-health-teams-staffing-establishment.md"};function i(o,t,l,h,r,f){return a(),n("div",null,[...t[0]||(t[0]=[s('<h1 id="_57a-community-health-teams-staffing-establishment" tabindex="-1">57A. Community Health Teams Staffing Establishment <a class="header-anchor" href="#_57a-community-health-teams-staffing-establishment" aria-label="Permalink to &quot;57A. Community Health Teams Staffing Establishment&quot;">​</a></h1><p><strong>(a)</strong> In the first 6 months from the operation of the Agreement, work will be undertaken by the parties and the Department of Health to map the staffing levels for community mental health teams and to record as a minimum staffing level for these services.</p><p><strong>(b)</strong> These minimum levels and change arrangements will be recorded in a MOU between the Department, VHIA and both Unions.</p><p><strong>(c)</strong> Backfill will remain subject to existing EBA provisions.</p><p><strong>(d)</strong> Where any change to the staffing level of the community mental health team of the unit is proposed the consultation processes of <a href="/eba/ebas/mental-health/common-terms/consultation-disputes/18-consultation.html">clause 18</a> (Consultation) will apply prior to any such change occurring.</p>',5)])])}const g=e(m,[["render",i]]);export{p as __pageData,g as default};
